<#
    .SYNOPSIS
        Windows Forms GUI for End-of-Life product information lookup.

    .DESCRIPTION
        This script provides a graphical user interface for checking End-of-Life information
        for various software products using the endoflife.date API. Users can select products
        from a list, view detailed EOL information, and export results to Excel.

        Based on this article: https://powershellisfun.com/2025/03/07/retrieve-end-of-life-information-using-powershell/

    .EXAMPLE
        .\Get-EndOfLife-GUI.ps1
        Launches the Windows Forms interface for End-of-Life product checking.

    .NOTES
        Author: Casper Stekelenburg
        Email: casper@dutchscriptingguys.com
        Date: April 09, 2026
        Requirements:
        - Windows operating system with .NET Framework
        - Internet connection for API access
        - ImportExcel module (installed automatically if needed for Excel export)

    .OUTPUTS
        None. This script provides a graphical interface and does not generate pipeline output.
#>

[CmdletBinding()]
[OutputType([System.Void])]
param()

Add-Type -AssemblyName System.Windows.Forms
Add-Type -AssemblyName System.Drawing
Add-Type -AssemblyName System.Data

#region Application Information
$Script:AppName = "End-of-Life Product Checker"
$Script:AppVersion = [version]"$((Get-Date).Year).$((Get-Date).Month).$((Get-Date).Day).$(Get-Date -Format 'HHmm')"
$Script:AppAuthor = "Casper Stekelenburg"
$Script:AppEmail = "casper@dutchscriptingguys.com"
#endregion Application Information

#region Global Variables
$Script:AllProducts = @()
$Script:FilteredProducts = @()
$Script:ProductDetails = @()
$Script:SelectedProducts = @()
$Script:StatusLabel = $null
$Script:MainForm = $null
$Script:ProductsListBox = $null
$Script:SearchTextBox = $null
$Script:GetDetailsButton = $null
$Script:LoadProductsButton = $null
$Script:ResultsDataGridView = $null
$Script:ExportMenuItem = $null
$Script:AboutMenuItem = $null
#endregion Global Variables

#region Functions
function Update-ProductFilter {
    <#
    .SYNOPSIS
        Filters the product list based on the search text.

    .DESCRIPTION
        Updates the products list box to show only products that match
        the search criteria entered by the user.

    .PARAMETER SearchText
        The text to filter products by.

    .OUTPUTS
        None. Updates the UI directly.
    #>
    [CmdletBinding()]
    [OutputType([System.Void])]
    param(
        [Parameter(HelpMessage = "Search text to filter products by")]
        [string]$SearchText = ""
    )    # Check if AllProducts is null, empty, or not properly initialized
    if ($null -eq $Script:AllProducts -or $Script:AllProducts.Count -eq 0) {
        # Clear the list box and show appropriate status
        if ($null -ne $Script:ProductsListBox) {
            $Script:ProductsListBox.Items.Clear()
        }
        if ($null -ne $Script:StatusLabel) {
            $Script:StatusLabel.Text = "No products loaded. Please load products first."
        }
        return
    }

    # Only proceed if ProductsListBox is initialized
    if ($null -eq $Script:ProductsListBox) {
        return
    }

    $Script:ProductsListBox.Items.Clear()

    if ([string]::IsNullOrWhiteSpace($SearchText)) {
        # Show all products if search is empty
        $Script:FilteredProducts = $Script:AllProducts
    } else {
        # Filter products by search text (case-insensitive)
        $Script:FilteredProducts = $Script:AllProducts | Where-Object {
            # Handle null/empty product names gracefully
            if ([string]::IsNullOrEmpty($_)) {
                return $false
            }
            $_ -like "*$SearchText*"
        }

        # Handle case where filter returns null or empty result
        if ($null -eq $Script:FilteredProducts) {
            $Script:FilteredProducts = @()
        }
    }

    # Ensure FilteredProducts is always an array and not null
    if ($null -eq $Script:FilteredProducts) {
        $Script:FilteredProducts = @()
    }

    # Only add items if there are any to add
    if ($Script:FilteredProducts.Count -gt 0) {
        $Script:ProductsListBox.Items.AddRange($Script:FilteredProducts)
    }

    # Update status (only if StatusLabel is initialized)
    if ($null -ne $Script:StatusLabel) {
        if ($Script:FilteredProducts.Count -eq 0 -and -not [string]::IsNullOrWhiteSpace($SearchText)) {
            $Script:StatusLabel.Text = "No products found matching '$SearchText'"
        } elseif ($Script:FilteredProducts.Count -ne $Script:AllProducts.Count) {
            $Script:StatusLabel.Text = "Showing $($Script:FilteredProducts.Count) of $($Script:AllProducts.Count) products"
        } else {
            $Script:StatusLabel.Text = "Loaded $($Script:AllProducts.Count) products"
        }
    }
}
function Get-ProductList {
    <#
    .SYNOPSIS
        Retrieves all available products from the endoflife.date API.

    .DESCRIPTION
        Fetches the complete list of products available for End-of-Life checking
        from the endoflife.date API and updates the global products list.

    .OUTPUTS
        [System.Boolean] Returns true if successful, false otherwise.
    #>
    [CmdletBinding()]
    [OutputType([System.Boolean])]
    param()

    try {
        Write-Verbose "Fetching all products from endoflife.date API"
        $ApiResult = Invoke-RestMethod -Uri "https://endoflife.date/api/all.json" -Method Get -ContentType 'application/json' -ErrorAction Stop

        # Check if API returned null or empty result
        if ($null -eq $ApiResult) {
            [System.Windows.Forms.MessageBox]::Show(
                "The API returned no data. Please try again later.",
                "No Data Received",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Warning
            )
            $Script:AllProducts = @()
            return $false
        }

        # Ensure result is an array and filter out null/empty entries
        if ($ApiResult -is [array]) {
            $Script:AllProducts = $ApiResult | Where-Object { -not [string]::IsNullOrEmpty($_) }
        } else {
            # Handle single item result
            if (-not [string]::IsNullOrEmpty($ApiResult)) {
                $Script:AllProducts = @($ApiResult)
            } else {
                $Script:AllProducts = @()
            }
        }

        # Final check if we have any valid products
        if ($Script:AllProducts.Count -eq 0) {
            [System.Windows.Forms.MessageBox]::Show(
                "No valid products were found in the API response.",
                "No Products Available",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Information
            )
            return $false
        }

        Write-Verbose "Successfully loaded $($Script:AllProducts.Count) products"
        return $true
    } catch {
        [System.Windows.Forms.MessageBox]::Show(
            "Could not retrieve product list. Please check your internet connection and try again.`n`nError: $($_.Exception.Message)",
            "Connection Error",
            [System.Windows.Forms.MessageBoxButtons]::OK,
            [System.Windows.Forms.MessageBoxIcon]::Error
        )
        $Script:AllProducts = @()
        return $false
    }
}
function Get-ProductDetail {
    <#
    .SYNOPSIS
        Retrieves detailed End-of-Life information for specified products.

    .DESCRIPTION
        Fetches detailed EOL information for the provided product list from
        the endoflife.date API and updates the global product details.

    .PARAMETER ProductList
        Array of product names to retrieve details for.

    .OUTPUTS
        [System.Boolean] Returns true if successful, false otherwise.
    #>
    [CmdletBinding()]
    [OutputType([System.Boolean])]
    param(
        [Parameter(Mandatory = $true,
            HelpMessage = "List of products to retrieve details for")]
        [ValidateNotNullOrEmpty()]
        [string[]]$ProductList
    )

    $Script:ProductDetails = @()
    $SuccessCount = 0
    $TotalCount = $ProductList.Count

    foreach ($Product in $ProductList) {
        try {
            Write-Verbose "Fetching details for product: $Product"
            $Results = Invoke-RestMethod -Uri "https://endoflife.date/api/$($Product).json" -Method Get -ContentType 'application/json' -ErrorAction Stop

            foreach ($Result in $Results) {
                $Script:ProductDetails += [PSCustomObject]@{
                    Product         = $Product
                    Cycle           = $Result.cycle
                    ReleaseDate     = $Result.releaseDate
                    EOL             = $Result.eol
                    Latest          = $Result.Latest
                    LTS             = $Result.LTS
                    Support         = $Result.support
                    ExtendedSupport = $Result.extendedSupport
                    Link            = $Result.link
                }
            }
            $SuccessCount++
        } catch {
            Write-Warning "Could not retrieve details for product: $Product"
        }
    }

    if ($SuccessCount -eq 0) {
        [System.Windows.Forms.MessageBox]::Show(
            "Could not retrieve details for any of the selected products. Please check your internet connection and try again.",
            "Data Retrieval Error",
            [System.Windows.Forms.MessageBoxButtons]::OK,
            [System.Windows.Forms.MessageBoxIcon]::Warning
        )
        return $false
    } elseif ($SuccessCount -lt $TotalCount) {
        [System.Windows.Forms.MessageBox]::Show(
            "Successfully retrieved details for $SuccessCount out of $TotalCount products. Some products may not be available or have connection issues.",
            "Partial Success",
            [System.Windows.Forms.MessageBoxButtons]::OK,
            [System.Windows.Forms.MessageBoxIcon]::Information
        )
    }

    return $true
}
function Export-ToExcel {
    <#
    .SYNOPSIS
        Exports product details to an Excel file.

    .DESCRIPTION
        Exports the current product details to an Excel file using the ImportExcel module.
        Installs the module if it's not already available. Optionally prompts to open the file.

    .PARAMETER FilePath
        Path to the Excel file to create.

    .PARAMETER PromptToOpen
        If specified, prompts the user to open the exported file.

    .OUTPUTS
        [System.Boolean] Returns true if successful, false otherwise.
    #>
    [CmdletBinding()]
    [OutputType([System.Boolean])]
    param(
        [Parameter(Mandatory = $true,
            HelpMessage = "Path to the Excel file to create")]
        [ValidateNotNullOrEmpty()]
        [string]$FilePath,

        [Parameter(HelpMessage = "Prompt user to open the exported file")]
        [switch]$PromptToOpen
    )

    try {
        # Install ImportExcel module if needed
        if (-not (Get-Module -Name ImportExcel -ListAvailable)) {
            Write-Verbose "Installing ImportExcel module"
            Install-Module ImportExcel -Scope CurrentUser -Force -ErrorAction Stop
        }
        Import-Module ImportExcel -ErrorAction Stop

        # Test path and remove empty file to avoid corruption
        New-Item -Path $FilePath -ItemType File -Force -ErrorAction Stop | Out-Null
        Remove-Item -Path $FilePath -Force | Out-Null

        # Export to Excel
        $Script:ProductDetails | Export-Excel -AutoSize -BoldTopRow -FreezeTopRow -AutoFilter -Path $FilePath

        if ($PromptToOpen) {
            $OpenFileResult = [System.Windows.Forms.MessageBox]::Show(
                "Successfully exported results to:`n$FilePath`n`nWould you like to open the file now?",
                "Export Successful",
                [System.Windows.Forms.MessageBoxButtons]::YesNo,
                [System.Windows.Forms.MessageBoxIcon]::Question
            )

            if ($OpenFileResult -eq [System.Windows.Forms.DialogResult]::Yes) {
                try {
                    Start-Process -FilePath $FilePath -ErrorAction Stop
                } catch {
                    [System.Windows.Forms.MessageBox]::Show(
                        "File exported successfully but could not open it.`n`nError: $($_.Exception.Message)",
                        "Open File Error",
                        [System.Windows.Forms.MessageBoxButtons]::OK,
                        [System.Windows.Forms.MessageBoxIcon]::Warning
                    )
                }
            }
        } else {
            [System.Windows.Forms.MessageBox]::Show(
                "Successfully exported results to:`n$FilePath",
                "Export Successful",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Information
            )
        }

        return $true
    } catch {
        [System.Windows.Forms.MessageBox]::Show(
            "Could not export results to Excel file.`n`nError: $($_.Exception.Message)",
            "Export Error",
            [System.Windows.Forms.MessageBoxButtons]::OK,
            [System.Windows.Forms.MessageBoxIcon]::Error
        )
        return $false
    }
}
