function Initialize-MainForm {
    <#
    .SYNOPSIS
        Creates and initializes the main Windows Form.

    .DESCRIPTION
        Sets up the main form with all controls and event handlers for the
        End-of-Life product checker GUI.

    .OUTPUTS
        [System.Windows.Forms.Form] The initialized main form.
    #>
    [CmdletBinding()]
    [OutputType([System.Windows.Forms.Form])]
    param()    # Create main form
    $Script:MainForm = New-Object System.Windows.Forms.Form
    $Script:MainForm.Text = "$($Script:AppName)"
    $Script:MainForm.Size = New-Object System.Drawing.Size(1000, 700)
    $Script:MainForm.StartPosition = "CenterScreen"
    $Script:MainForm.MinimumSize = New-Object System.Drawing.Size(800, 500)
    try {
        $iconBase64 = ""

        # Convert base64 to byte array
        $iconBytes = [Convert]::FromBase64String($iconBase64)
        # Create memory stream and load icon
        $memoryStream = New-Object System.IO.MemoryStream
        $memoryStream.Write($iconBytes, 0, $iconBytes.Length)
        $memoryStream.Seek(0, [System.IO.SeekOrigin]::Begin) | Out-Null

        # Create and assign the icon
        $Script:MainForm.Icon = New-Object System.Drawing.Icon($memoryStream)
        $Script:MainForm.ShowIcon = $true

        # Clean up memory stream
        $memoryStream.Close()
        $memoryStream.Dispose()
    } catch {
        Write-Warning "Could not load embedded icon: $($_.Exception.Message)"
        # Fallback to system icon
        $Script:MainForm.Icon = [System.Drawing.SystemIcons]::Application
        $Script:MainForm.ShowIcon = $true
    }
    # Create status bar
    $StatusBar = New-Object System.Windows.Forms.StatusStrip
    $Script:StatusLabel = New-Object System.Windows.Forms.ToolStripStatusLabel
    $Script:StatusLabel.Text = "Ready"
    $StatusBar.Items.Add($Script:StatusLabel) | Out-Null
    $Script:MainForm.Controls.Add($StatusBar)
    # Create main menu
    $MenuStrip = New-Object System.Windows.Forms.MenuStrip
    $FileMenu = New-Object System.Windows.Forms.ToolStripMenuItem
    $FileMenu.Text = "&File"

    $Script:ExportMenuItem = New-Object System.Windows.Forms.ToolStripMenuItem
