    $FileMenu.DropDownItems.AddRange(@($Script:ExportMenuItem, $ExitMenuItem))
    $MenuStrip.Items.Add($FileMenu) | Out-Null

    # Create Help menu
    $HelpMenu = New-Object System.Windows.Forms.ToolStripMenuItem
    $HelpMenu.Text = "&Help"

    $Script:AboutMenuItem = New-Object System.Windows.Forms.ToolStripMenuItem
    $Script:AboutMenuItem.Text = "&About..."
