    $Script:GetDetailsButton.Enabled = $false

    $TopTablePanel.Controls.Add($Script:LoadProductsButton, 1, 0)
    $TopTablePanel.Controls.Add($SearchPanel, 0, 1)
    $TopTablePanel.Controls.Add($Script:ProductsListBox, 0, 2)
    $TopTablePanel.Controls.Add($Script:GetDetailsButton, 1, 2)
    $TopTablePanel.SetRowSpan($Script:ProductsListBox, 1)

    $TopPanel.Controls.Add($TopTablePanel)
    $MainPanel.Controls.Add($TopPanel, 0, 0)    # Create bottom panel for results
    $BottomPanel = New-Object System.Windows.Forms.GroupBox
    $BottomPanel.Text = "End-of-Life Details"
    $BottomPanel.Dock = [System.Windows.Forms.DockStyle]::Fill
    $BottomPanel.Padding = New-Object System.Windows.Forms.Padding(10)

    # Results data grid view
    $Script:ResultsDataGridView = New-Object System.Windows.Forms.DataGridView
    $Script:ResultsDataGridView.Dock = [System.Windows.Forms.DockStyle]::Fill
    $Script:ResultsDataGridView.AutoSizeColumnsMode = [System.Windows.Forms.DataGridViewAutoSizeColumnsMode]::Fill
    $Script:ResultsDataGridView.ReadOnly = $true
    $Script:ResultsDataGridView.AllowUserToAddRows = $false
    $Script:ResultsDataGridView.AllowUserToDeleteRows = $false
    $Script:ResultsDataGridView.SelectionMode = [System.Windows.Forms.DataGridViewSelectionMode]::FullRowSelect
    $Script:ResultsDataGridView.MultiSelect = $true

    $BottomPanel.Controls.Add($Script:ResultsDataGridView)
    $MainPanel.Controls.Add($BottomPanel, 0, 1)

    # Event handlers
    $Script:LoadProductsButton.Add_Click({
            $Script:StatusLabel.Text = "Loading products..."
            $Script:LoadProductsButton.Enabled = $false
            $Script:MainForm.Cursor = [System.Windows.Forms.Cursors]::WaitCursor

            if (Get-ProductList) {
                # Initialize the filtered products and update the UI
                Update-ProductFilter -SearchText ""
                $Script:GetDetailsButton.Enabled = $true
            } else {
                $Script:StatusLabel.Text = "Failed to load products"
            }

            $Script:LoadProductsButton.Enabled = $true
            $Script:MainForm.Cursor = [System.Windows.Forms.Cursors]::Default
        })
    $Script:GetDetailsButton.Add_Click({
            if ($Script:ProductsListBox.SelectedItems.Count -eq 0) {
                [System.Windows.Forms.MessageBox]::Show(
                    "Please select one or more products from the list.",
                    "No Selection",
                    [System.Windows.Forms.MessageBoxButtons]::OK,
                    [System.Windows.Forms.MessageBoxIcon]::Information
                )
                return
            }

            $SelectedProducts = @()
            foreach ($Item in $Script:ProductsListBox.SelectedItems) {
                $SelectedProducts += $Item.ToString()
            }

            $Script:StatusLabel.Text = "Retrieving EOL details..."
            $Script:GetDetailsButton.Enabled = $false
            $Script:MainForm.Cursor = [System.Windows.Forms.Cursors]::WaitCursor
            if (Get-ProductDetail -ProductList $SelectedProducts) {
                # Convert to DataTable for better binding
                $DataTable = New-Object System.Data.DataTable

                if ($Script:ProductDetails.Count -gt 0) {
                    # Add columns based on first object
                    $FirstItem = $Script:ProductDetails[0]
                    foreach ($Property in $FirstItem.PSObject.Properties.Name) {
                        $DataTable.Columns.Add($Property) | Out-Null
                    }

                    # Add rows
                    foreach ($Item in $Script:ProductDetails) {
                        $Row = $DataTable.NewRow()
                        foreach ($Property in $Item.PSObject.Properties.Name) {
                            $Row[$Property] = $Item.$Property
                        }
                        $DataTable.Rows.Add($Row)
                    }

                    $Script:ResultsDataGridView.DataSource = $DataTable
                }

                $Script:StatusLabel.Text = "Retrieved details for $($Script:ProductDetails.Count) product cycles"
                $Script:ExportMenuItem.Enabled = $true
            } else {
                $Script:StatusLabel.Text = "Failed to retrieve product details"
            }

            $Script:GetDetailsButton.Enabled = $true
            $Script:MainForm.Cursor = [System.Windows.Forms.Cursors]::Default
        })
    $Script:ExportMenuItem.Add_Click({
            if ($Script:ProductDetails.Count -eq 0) {
                [System.Windows.Forms.MessageBox]::Show(
                    "No data to export. Please retrieve product details first.",
                    "No Data",
                    [System.Windows.Forms.MessageBoxButtons]::OK,
                    [System.Windows.Forms.MessageBoxIcon]::Information
                )
                return
            }

            $SaveFileDialog = New-Object System.Windows.Forms.SaveFileDialog
            $SaveFileDialog.Filter = "Excel Files (*.xlsx)|*.xlsx"
            $SaveFileDialog.Title = "Export End-of-Life Data"
            $SaveFileDialog.FileName = "EndOfLife-$(Get-Date -Format 'yyyyMMdd-HHmmss').xlsx"
            if ($SaveFileDialog.ShowDialog() -eq [System.Windows.Forms.DialogResult]::OK) {
                $Script:StatusLabel.Text = "Exporting to Excel..."
                $Script:MainForm.Cursor = [System.Windows.Forms.Cursors]::WaitCursor

                Export-ToExcel -FilePath $SaveFileDialog.FileName -PromptToOpen

                $Script:StatusLabel.Text = "Export completed"
                $Script:MainForm.Cursor = [System.Windows.Forms.Cursors]::Default
            }
        })

    $ExitMenuItem.Add_Click({
            $Script:MainForm.Close()
        })

    $Script:AboutMenuItem.Add_Click({
            Show-AboutDialog
        })

    # Initialize status
    $Script:ExportMenuItem.Enabled = $false

    return $Script:MainForm
}
#endregion Functions

#region Main Process
try {
    Write-Verbose "Initializing End-of-Life Checker GUI"
    # Create and show the main form
    $MainForm = Initialize-MainForm
    $MainForm.Add_Shown({ $MainForm.Activate() })
    [System.Windows.Forms.Application]::Run($MainForm)
} catch {
    Write-Error "An error occurred while running the GUI: $_"
    exit 1
}
#endregion Main Process
